28	/// Derive project name from a repo argument.
29	///
30	/// Handles: `owner/name`, `git@github.com:owner/name.git`,
31	/// `https://github.com/owner/name.git`, `https://github.com/owner/name`
32	fn derive_name(repo: &str) -> Result<String, Box<dyn std::error::Error>> {
33	    // Strip trailing .git
34	    let repo = repo.strip_suffix(".git").unwrap_or(repo);
35	
36	    // Take everything after the last `/` or `:`
37	    let name = repo
38	        .rsplit_once('/')
39	        .or_else(|| repo.rsplit_once(':'))
40	        .map(|(_, name)| name)
41	        .unwrap_or(repo);
42	
43	    if name.is_empty() {
44	        return Err(format!("cannot derive project name from '{repo}'").into());
45	    }
46	    Ok(name.to_string())
47	}
48	
49	/// Resolve a repo argument to a git clone URL.
50	///
51	/// `owner/name` (no scheme, no `:` before `/`) becomes `git@github.com:owner/name.git`.
52	/// Anything else is passed through as-is.
53	fn resolve_url(repo: &str) -> String {
54	    // Already a URL (has scheme or SSH-style colon)
55	    if repo.contains("://") || repo.contains('@') {
56	        return repo.to_string();
57	    }
58	    // owner/name shorthand — must have exactly one `/` and no other URL indicators
59	    if repo.matches('/').count() == 1 && !repo.contains(':') {
60	        return format!("git@github.com:{repo}.git");
61	    }
62	    repo.to_string()
63	}
