65	pub fn clone_repo(args: &CloneArgs) -> Result<(), Box<dyn std::error::Error>> {
66	    log::debug!("clone: enter");
67	    let parent_dir = match &args.dir {
68	        Some(d) => d.clone(),
69	        None => std::env::current_dir()?,
70	    };
71	
72	    let name = match &args.name {
73	        Some(n) => n.clone(),
74	        None => derive_name(&args.repo)?,
75	    };
76	    let project_dir = parent_dir.join(&name);
77	    let session_dir = project_dir.join(".claude");
78	    let url = resolve_url(&args.repo);
79	
80	    if args.dry_run {
81	        info!("Dry run — would execute:");
82	        info!("  1. git clone --recursive {url} {name}");
83	        info!("  2. jj git init --colocate in {name}/");
84	        info!("  3. jj git init --colocate in {name}/.claude/");
85	        info!("  4. Create Claude Code symlink");
86	        return Ok(());
87	    }
88	
89	    // Preflight
90	    if project_dir.exists() {
91	        return Err(format!("'{}' already exists", project_dir.display()).into());
92	    }
93	
94	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
95	
96	    // Step 1: git clone --recursive
97	    let project_str = project_dir
98	        .to_str()
99	        .ok_or("project path is not valid UTF-8")?;
100	    info!("Step 1: Cloning {url}...");
101	    run(
102	        "git",
103	        &["clone", "--recursive", &url, project_str],
104	        &parent_dir,
105	    )?;
106	
107	    // Step 2: jj git init --colocate in code repo
108	    info!("Step 2: Initializing jj in code repo...");
109	    run("jj", &["git", "init", "--colocate"], &project_dir)?;
110	
111	    // Step 3: jj git init --colocate in session repo (if submodule exists)
112	    if session_dir.exists() {
113	        info!("Step 3: Initializing jj in session repo...");
114	        run("jj", &["git", "init", "--colocate"], &session_dir)?;
115	    } else {
116	        info!("Step 3: No .claude submodule found — skipping session repo jj init");
117	    }
118	
119	    // Step 4: Create Claude Code symlink
120	    info!("Step 4: Creating Claude Code symlink...");
121	    let symlink_dir = {
122	        let home =
123	            std::env::var("HOME").map_err(|_| "HOME environment variable not set".to_string())?;
124	        PathBuf::from(home).join(".claude").join("projects")
125	    };
126	
127	    let sl = symlink::SymLink::new(&project_dir, Path::new(".claude"), &symlink_dir)?;
128	    sl.create(false)?;
129	
130	    info!("");
131	    info!("Done! Project cloned to {}", project_dir.display());
132	    info!("  Code repo:    {project_str}");
133	    info!("  Session repo: {}", session_dir.display());
134	    info!(
135	        "  Symlink:      {} -> {}",
136	        sl.symlink_path.display(),
137	        sl.abs_target.display()
138	    );
139	
140	    log::debug!("clone: exit");
141	    Ok(())
142	}
