39	/// Run a command with retries, sleeping between attempts.
40	fn run_retry(
41	    cmd: &str,
42	    args: &[&str],
43	    cwd: &Path,
44	    retries: u32,
45	    delay_secs: u64,
46	) -> Result<String, Box<dyn std::error::Error>> {
47	    let mut last_err = String::new();
48	    for attempt in 1..=retries {
49	        match run(cmd, args, cwd) {
50	            Ok(out) => {
51	                if attempt > 1 {
52	                    debug!("succeeded after {attempt} attempts");
53	                }
54	                return Ok(out);
55	            }
56	            Err(e) => {
57	                last_err = e.to_string();
58	                if attempt < retries {
59	                    debug!("attempt {attempt}/{retries} failed: {last_err}");
60	                    debug!("retrying in {delay_secs}s...");
61	                    std::thread::sleep(std::time::Duration::from_secs(delay_secs));
62	                }
63	            }
64	        }
65	    }
66	    Err(format!("failed after {retries} attempts: {last_err}").into())
67	}
