71	/// Get the short (12-char) jj change ID for a revision, without printing.
72	fn jj_chid(rev: &str, cwd: &Path) -> Result<String, Box<dyn std::error::Error>> {
73	    let full = run(
74	        "jj",
75	        &[
76	            "log",
77	            "-r",
78	            rev,
79	            "--no-graph",
80	            "-T",
81	            "change_id",
82	            "--limit",
83	            "1",
84	        ],
85	        cwd,
86	    )?;
87	    Ok(full[..full.len().min(12)].to_string())
88	}
