133	pub fn init(args: &InitArgs) -> Result<(), Box<dyn std::error::Error>> {
134	    debug!("init: enter");
135	    let parent_dir = match &args.dir {
136	        Some(d) => d.clone(),
137	        None => std::env::current_dir()?,
138	    };
139	    let project_dir = parent_dir.join(&args.name);
140	    let session_dir = project_dir.join(".claude");
141	
142	    // Preflight checks
143	    info!("Preflight checks...");
144	
145	    // Check tools
146	    run("gh", &["auth", "status"], Path::new("."))
147	        .map_err(|_| "gh is not installed or not authenticated (run: gh auth login)")?;
148	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
149	
150	    let owner = match &args.owner {
151	        Some(o) => o.clone(),
152	        None => gh_whoami()?,
153	    };
154	
155	    if project_dir.exists() {
156	        return Err(format!("'{}' already exists", project_dir.display()).into());
157	    }
158	
159	    let code_repo = format!("{owner}/{}", args.name);
160	    let session_repo = format!("{owner}/{}.claude", args.name);
161	
162	    if gh_repo_exists(&owner, &args.name)? {
163	        return Err(format!("GitHub repo '{code_repo}' already exists").into());
164	    }
165	    if gh_repo_exists(&owner, &format!("{}.claude", args.name))? {
166	        return Err(format!("GitHub repo '{session_repo}' already exists").into());
167	    }
168	
169	    let visibility = if args.private {
170	        "--private"
171	    } else {
172	        "--public"
173	    };
174	
175	    if args.dry_run {
176	        info!("Dry run — would execute:");
177	        info!("  1. Create directories: {}", project_dir.display());
178	        info!("  2. git init + jj git init --colocate on both repos");
179	        info!("  3. Write .vc-config.toml and .gitignore to both");
180	        info!("  4. jj commit both with placeholder ochids");
181	        info!("  5. Get both chids, jj describe both with correct ochids");
182	        info!("  6. Remove jj from both (git clean -xdf)");
183	        info!("  7. gh repo create {session_repo} {visibility}, push");
184	        info!("  8. git submodule add .claude, second commit in code repo");
185	        info!("  9. gh repo create {code_repo} {visibility}, push");
186	        info!("  10. jj git init --colocate on both repos");
187	        info!("  11. Create Claude Code symlink");
188	        return Ok(());
189	    }
190	
191	    // Step 1: Create directories
192	    info!("Step 1: Creating project directories...");
193	    mkdir_p(&project_dir)?;
194	    mkdir_p(&session_dir)?;
195	
196	    // Step 2: git init + jj init on both repos
197	    info!("Step 2: Initializing repos...");
198	    run("git", &["init"], &project_dir)?;
199	    run("jj", &["git", "init", "--colocate"], &project_dir)?;
200	    run("git", &["init"], &session_dir)?;
201	    run("jj", &["git", "init", "--colocate"], &session_dir)?;
202	
203	    // Step 3: Write config files
204	    info!("Step 3: Writing config files...");
205	    write_file(&project_dir.join(".vc-config.toml"), VC_CONFIG_CODE)?;
206	    write_file(&project_dir.join(".gitignore"), GITIGNORE_CODE)?;
207	    write_file(&session_dir.join(".vc-config.toml"), VC_CONFIG_SESSION)?;
208	    write_file(&session_dir.join(".gitignore"), GITIGNORE_SESSION)?;
209	
210	    // Step 4: jj commit both with placeholder ochids
211	    info!("Step 4: Committing both repos with placeholder ochids...");
212	    run(
213	        "jj",
214	        &["commit", "-m", "Initial commit\n\nochid: /none"],
215	        &project_dir,
216	    )?;
217	    run(
218	        "jj",
219	        &["commit", "-m", "Initial commit\n\nochid: /none"],
220	        &session_dir,
221	    )?;
222	
223	    // Step 5: Get both chids, then describe both with correct ochids
224	    info!("Step 5: Setting ochid cross-references...");
225	    let code_chid = jj_chid("@-", &project_dir)?;
226	    let session_chid = jj_chid("@-", &session_dir)?;
227	
228	    let code_desc = format!("Initial commit\n\nochid: /.claude/{session_chid}");
229	    let session_desc = format!("Initial commit\n\nochid: /{code_chid}");
230	    run("jj", &["describe", "@-", "-m", &code_desc], &project_dir)?;
231	    run("jj", &["describe", "@-", "-m", &session_desc], &session_dir)?;
232	
233	    {
234	        let hash = run("git", &["rev-parse", "HEAD"], &project_dir)?;
235	        debug!("code repo: chid={code_chid} hash={hash}");
236	        let hash = run("git", &["rev-parse", "HEAD"], &session_dir)?;
237	        debug!(".claude:   chid={session_chid} hash={hash}");
238	    }
239	
240	    // Step 6: Set bookmarks (creates git branches), then remove jj
241	    // Bookmarks must be set before removing .jj/ so git has a 'main' branch to push
242	    info!("Step 6: Setting bookmarks and removing jj...");
243	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
244	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
245	    // Clean .claude first, then code repo with --exclude to preserve .claude/
246	    run("git", &["clean", "-xdf"], &session_dir)?;
247	    run(
248	        "git",
249	        &["clean", "-xdf", "--exclude", ".claude"],
250	        &project_dir,
251	    )?;
252	    // After removing .jj/, git HEAD is detached — reattach to main
253	    run("git", &["checkout", "main"], &session_dir)?;
254	    run("git", &["checkout", "main"], &project_dir)?;
255	
256	    // Step 7: Create .claude GitHub repo and push
257	    let session_url = format!("git@github.com:{session_repo}.git");
258	    info!("Step 7: Creating GitHub repo {session_repo}...");
259	    run(
260	        "gh",
261	        &["repo", "create", &session_repo, visibility],
262	        &project_dir,
263	    )?;
264	    run(
265	        "git",
266	        &["remote", "add", "origin", &session_url],
267	        &session_dir,
268	    )?;
269	    run_retry(
270	        "git",
271	        &["push", "-u", "origin", "main"],
272	        &session_dir,
273	        args.push_retries,
274	        args.push_retry_delay,
275	    )?;
276	
277	    // Step 8: Add .claude as submodule — second commit in code repo
278	    info!("Step 8: Adding .claude as submodule...");
279	    // Remove .claude directory so git submodule add can re-clone it
280	    std::fs::remove_dir_all(&session_dir)?;
281	    run(
282	        "git",
283	        &["submodule", "add", "--force", &session_url, ".claude"],
284	        &project_dir,
285	    )?;
286	    let submodule_body = format!("Add .claude submodule\n\nochid: /.claude/{session_chid}");
287	    run("git", &["add", "."], &project_dir)?;
288	    run("git", &["commit", "-m", &submodule_body], &project_dir)?;
289	
290	    // Step 9: Create code GitHub repo and push
291	    let code_url = format!("git@github.com:{code_repo}.git");
292	    info!("Step 9: Creating GitHub repo {code_repo}...");
293	    run(
294	        "gh",
295	        &["repo", "create", &code_repo, visibility],
296	        &project_dir,
297	    )?;
298	    run("git", &["remote", "add", "origin", &code_url], &project_dir)?;
299	    run_retry(
300	        "git",
301	        &["push", "-u", "origin", "main"],
302	        &project_dir,
303	        args.push_retries,
304	        args.push_retry_delay,
305	    )?;
306	
307	    // Step 10: Re-initialize jj on both repos
308	    info!("Step 10: Re-initializing jj on both repos...");
309	    run("jj", &["git", "init", "--colocate"], &project_dir)?;
310	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &project_dir)?;
311	    run("jj", &["bookmark", "track", "main@origin"], &project_dir)?;
312	    let code_chid_final = jj_chid("@-", &project_dir)?;
313	
314	    run("jj", &["git", "init", "--colocate"], &session_dir)?;
315	    run("jj", &["bookmark", "set", "main", "-r", "@-"], &session_dir)?;
316	    run("jj", &["bookmark", "track", "main@origin"], &session_dir)?;
317	    let session_chid_final = jj_chid("@-", &session_dir)?;
318	
319	    // Step 11: Create Claude Code symlink
320	    info!("Step 11: Creating Claude Code symlink...");
321	    let symlink_dir = {
322	        let home =
323	            std::env::var("HOME").map_err(|_| "HOME environment variable not set".to_string())?;
324	        PathBuf::from(home).join(".claude").join("projects")
325	    };
326	
327	    let sl = symlink::SymLink::new(&project_dir, Path::new(".claude"), &symlink_dir)?;
328	    sl.create(false)?;
329	
330	    info!("");
331	    info!("Done! Project created at {}", project_dir.display());
332	    info!("  Code repo:    {code_repo}  (chid={code_chid_final})");
333	    info!("  Session repo: {session_repo}  (chid={session_chid_final})");
334	    info!(
335	        "  Symlink:      {} -> {}",
336	        sl.symlink_path.display(),
337	        sl.abs_target.display()
338	    );
339	
340	    debug!("init: exit");
341	    Ok(())
342	}
