80	fn show_one_commit(
81	    commit: &Commit,
82	    workspace: &Workspace,
83	    repo: &Arc<ReadonlyRepo>,
84	    file_limit: FileLimit,
85	    is_primary: bool,
86	) -> Result<(), Box<dyn std::error::Error>> {
87	    // Author
88	    let author = commit.author();
89	    info!(
90	        "Author:    {} <{}> ({})",
91	        author.name,
92	        author.email,
93	        format_timestamp(&author.timestamp)
94	    );
95	
96	    // Committer
97	    let committer = commit.committer();
98	    info!(
99	        "Committer: {} <{}> ({})",
100	        committer.name,
101	        committer.email,
102	        format_timestamp(&committer.timestamp)
103	    );
104	
105	    // Ids
106	    let ids_line = common::format_commit_short(commit);
107	    if is_primary {
108	        info!("Ids:       {}", common::bold(&ids_line));
109	    } else {
110	        info!("Ids:       {ids_line}");
111	    }
112	
113	    // Parents
114	    let root_commit_id = repo.store().root_commit_id().clone();
115	    for parent_id in commit.parent_ids() {
116	        if *parent_id == root_commit_id {
117	            continue;
118	        }
119	        let parent = repo.store().get_commit(parent_id)?;
120	        info!("Parent:    {}", common::format_commit_short(&parent));
121	    }
122	
123	    // Children
124	    let children_ids =
125	        common::resolve_revset(workspace, repo, &format!("children({})", commit.id().hex()))?;
126	    for child_id in &children_ids {
127	        if *child_id == root_commit_id {
128	            continue;
129	        }
130	        let child = repo.store().get_commit(child_id)?;
131	        info!("Child:     {}", common::format_commit_short(&child));
132	    }
133	
134	    // Branches
135	    let branches_str = format_branches(commit, workspace, repo)?;
136	    info!("Branches:  {branches_str}");
137	
138	    // Follows
139	    let follows = find_nearest_tag(commit, workspace, repo, true)?;
140	    info!("Follows:   {}", follows.as_deref().unwrap_or(""));
141	
142	    // Precedes
143	    let precedes = find_nearest_tag(commit, workspace, repo, false)?;
144	    info!("Precedes:  {}", precedes.as_deref().unwrap_or(""));
145	
146	    // Description (body only — title is on the Ids line)
147	    print_description(commit);
148	
149	    // Changed files
150	    if file_limit != FileLimit::None {
151	        print_diff(commit, repo, file_limit)?;
152	    }
153	
154	    Ok(())
155	}
