157	fn find_nearest_tag(
158	    commit: &Commit,
159	    workspace: &Workspace,
160	    repo: &Arc<ReadonlyRepo>,
161	    ancestor: bool,
162	) -> Result<Option<String>, Box<dyn std::error::Error>> {
163	    let commit_hex = commit.id().hex();
164	
165	    let revset_str = if ancestor {
166	        format!("heads(tags() & ::{})", commit_hex)
167	    } else {
168	        format!("roots(tags() & {}::)", commit_hex)
169	    };
170	
171	    let tag_ids = common::resolve_revset(workspace, repo, &revset_str)?;
172	    if tag_ids.is_empty() {
173	        return Ok(None);
174	    }
175	
176	    let tag_id = &tag_ids[0];
177	    let view = repo.view();
178	    for (name, local_remote) in view.tags() {
179	        if local_remote.local_target.added_ids().any(|id| id == tag_id) {
180	            return Ok(Some(name.as_str().to_string()));
181	        }
182	    }
183	
184	    Ok(None)
185	}
