187	fn format_branches(
188	    commit: &Commit,
189	    workspace: &Workspace,
190	    repo: &Arc<ReadonlyRepo>,
191	) -> Result<String, Box<dyn std::error::Error>> {
192	    let commit_hex = commit.id().hex();
193	    let view = repo.view();
194	    let mut names: Vec<String> = Vec::new();
195	
196	    for (name, local_remote) in view.bookmarks() {
197	        for bookmark_id in local_remote.local_target.added_ids() {
198	            let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
199	            let results = common::resolve_revset(workspace, repo, &revset_str)?;
200	            if !results.is_empty() {
201	                names.push(name.as_str().to_string());
202	                break;
203	            }
204	        }
205	
206	        for (remote_name, remote_ref) in &local_remote.remote_refs {
207	            if remote_name.as_str() == "git" {
208	                continue;
209	            }
210	            for bookmark_id in remote_ref.target.added_ids() {
211	                let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
212	                let results = common::resolve_revset(workspace, repo, &revset_str)?;
213	                if !results.is_empty() {
214	                    names.push(format!("{}@{}", name.as_str(), remote_name.as_str()));
215	                    break;
216	                }
217	            }
218	        }
219	    }
220	
221	    Ok(names.join(", "))
222	}
