253	fn print_diff(
254	    commit: &Commit,
255	    repo: &Arc<ReadonlyRepo>,
256	    file_limit: FileLimit,
257	) -> Result<(), Box<dyn std::error::Error>> {
258	    let parent_tree = commit.parent_tree(repo.as_ref()).block_on()?;
259	    let commit_tree = commit.tree();
260	
261	    let diff_iter = TreeDiffIterator::new(&parent_tree, &commit_tree, &EverythingMatcher);
262	
263	    let mut lines: Vec<String> = Vec::new();
264	    for entry in diff_iter {
265	        let diff = entry.values?;
266	        let before = diff.before.as_resolved().cloned().flatten();
267	        let after = diff.after.as_resolved().cloned().flatten();
268	
269	        if matches!(&before, Some(TreeValue::Tree(_))) || matches!(&after, Some(TreeValue::Tree(_)))
270	        {
271	            continue;
272	        }
273	
274	        let path_str = entry.path.as_internal_file_string().to_string();
275	
276	        let line = match (before, after) {
277	            (None, Some(value)) => {
278	                format!("    Added {} {path_str}", file_type_str(&value))
279	            }
280	            (Some(_), None) => {
281	                format!(
282	                    "    Removed {} {path_str}",
283	                    file_type_str_from_merged(&diff.before),
284	                )
285	            }
286	            (Some(_), Some(value)) => {
287	                format!("    Modified {} {path_str}", file_type_str(&value))
288	            }
289	            (None, None) => continue,
290	        };
291	        lines.push(line);
292	    }
293	
294	    let total = lines.len();
295	    let cap = match file_limit {
296	        FileLimit::All | FileLimit::None => 0,
297	        FileLimit::Cap(n) => n,
298	    };
299	    let show_all = cap == 0 || total <= cap;
300	
301	    if show_all {
302	        info!("Changed files: {total}");
303	        for line in &lines {
304	            info!("{line}");
305	        }
306	    } else {
307	        info!("Changed files: {total}, showing first {cap}");
308	        for line in &lines[..cap] {
309	            info!("{line}");
310	        }
311	    }
312	
313	    Ok(())
314	}
