316	fn file_type_str(value: &TreeValue) -> &'static str {
317	    match value {
318	        TreeValue::File {
319	            executable: false, ..
320	        } => "regular file",
321	        TreeValue::File {
322	            executable: true, ..
323	        } => "executable file",
324	        TreeValue::Symlink(_) => "symlink",
325	        TreeValue::Tree(_) => "tree",
326	        TreeValue::GitSubmodule(_) => "git submodule",
327	    }
328	}
