330	fn file_type_str_from_merged(merged: &jj_lib::merge::Merge<Option<TreeValue>>) -> &'static str {
331	    if let Some(Some(value)) = merged.as_resolved() {
332	        file_type_str(value)
333	    } else {
334	        "file"
335	    }
336	}
